  ('diplomatic-0471a791-moex-00052', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-114-7f4830a9', 'sub-diplomatic-0471a791-03', NULL, 'single_choice', '關於清朝末年中法越南戰爭，下列敘述何者正確？', '["同治年間，法國殖民者已實際控制越南中南部", "清廷內部分為和、戰兩派，李鴻章積極主戰", "光緒10年（1884年），法國艦隊炮擊基隆、封鎖臺灣，當時負責臺灣軍務的是沈葆楨", "光緒11年（1885年），劉永福率領黑旗軍，於廣西鎮南關、越北諒山等地，連戰皆捷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:14+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00053', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-114-7f4830a9', 'sub-diplomatic-0471a791-03', NULL, 'single_choice', '關於義和團之亂與八國聯軍，下列敘述何者正確？', '["義和團源自白蓮教，最早流行於河南一帶", "義和團的活動，一度引起德國的抗議，清廷乃派袁世凱南來，認真督剿", "八國聯軍出兵後，共推俄國將領瓦德西（AlfredvonWaldersee）為聯軍統帥", "八國聯軍占領北京後，東南各省督撫提倡「自保」運動，以曾國藩為首領銜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:14+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
