  ('diplomatic-0471a791-moex-00059', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-114-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '依憲法及增修條文規定，下列關於考試院之敘述，何者正確？', '["憲法明定考試委員名額", "考試院得向立法院提出法律案", "憲法增修條文明定考試委員任期四年", "考試委員由立法院依政黨比例提名"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:14+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00060', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-114-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '依司法院釋字第 689 號解釋，判斷立法者制定之法定程序，是否符合憲法上正當法律程序原則之要 求，應考量之因素不包括下列何者？', '["人民權利受侵害或限制時，應有使其獲得救濟之機會與制度", "所涉基本權之種類、限制之強度及範圍、所欲追求之公共利益、決定機關之功能合適性", "有無替代程序或各項可能程序成本", "法律安定性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:14+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00061', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-114-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '依原住民身分法規定，下列各選項中之丙，何者原本無法取得原住民身分，然已被憲法法庭判決宣告 該規定違憲？', '["原住民甲與原住民乙結婚所生，從乙之姓氏之女丙", "原住民甲與非原住民乙結婚所生，從甲之姓氏之子丙", "原住民甲與非原住民乙結婚所生，從乙之姓氏之女丙", "原住民甲與非原住民乙結婚所生，從具原住民傳統名字之女丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:14+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL)
